sql:
SELECT suspect_id, LOWER(name) AS name, date_of_birth, gender, email, address, phone_number, known_aliases, arrest_history, last_known_location, status
FROM suspects
WHERE gender = 'F' AND status != 'active';

external_knowledge:
- "Identities" refers to the full names of suspects;
- "Past arrest records" refers to the non-empty arrest histories of suspects;
- "Involved in prior incidents" refers to suspects with non-null and non-empty arrest history entries;
- "Born more recently" refers to ordering by date of birth in descending order.

